const n = []; for(let i=1; i<=30; i+=0.5) { n.push(i); }

const o_1 = n.map(() => 1);
const o_log_n = n.map(v => Math.log2(v));
const o_n = n.map(v => v);
const o_n_log_n = n.map(v => v * Math.log2(v));
const o_n_2 = n.map(v => Math.pow(v, 2));
const o_2_n = n.map(v => Math.pow(2, v));

const createTrace = (x, y, name, color, dash) => ({
  x, y, name, 
  type: 'scatter', 
  mode: 'lines', 
  line: { color, width: 3, dash: dash || 'solid' },
  hovertemplate: `<b>${name}</b><br>n: %{x}<br>Ops: %{y:.2f}<extra></extra>`
});

return [
  createTrace(n, o_1, 'O(1) - Constant', '#94a3b8', 'dot'),
  createTrace(n, o_log_n, 'O(log n) - Logarithmic', '#10b981'),
  createTrace(n, o_n, 'O(n) - Linear', '#3b82f6'),
  createTrace(n, o_n_log_n, 'O(n log n) - Linearithmic', '#8b5cf6'),
  createTrace(n, o_n_2, 'O(n²) - Quadratic', '#f59e0b'),
  createTrace(n, o_2_n, 'O(2ⁿ) - Exponential', '#ef4444')
];
